	TB_DEVICE 
SET 
	lavelNo = #{lavelNo} 
	, bluetoothNo = #{bluetoothNo} 

	, password = #{password} 

	, usimNo = #{usimNo} 
	, machineNumber = #{machineNumber} 
	, weContact = #{weContact} 
	, tabletManager = #{tabletManager} 
	, startDate = #{startDate} 
	, endDate = #{endDate} 
WHERE id = #{id}
